import { useState, useEffect } from "react";
import NavbarGestionSalas from "../components/NavbarGestionSalas";
import "../styles/GestionarSalas.css";

function GestionarSalas({ user }) {
  const [salas, setSalas] = useState([]);
  const [showModal, setShowModal] = useState(false);

  const [selectedSala, setSelectedSala] = useState(null);
  const [showInfoModal, setShowInfoModal] = useState(false);

  // 🔥 EDITAR
  const [showEditModal, setShowEditModal] = useState(false);
  const [editTab, setEditTab] = useState("info");

  const [editForm, setEditForm] = useState({
    nombre: "",
    ubicacion: "",
    capacidad: ""
  });

  const [editEstado, setEditEstado] = useState("");

  // 🔥 CREAR
  const [sala, setSala] = useState({
    id: "",
    nombre: "",
    ubicacion: "",
    capacidad: ""
  });

  const obtenerSalas = async () => {
    try {
      const response = await fetch("http://localhost:3001/api/salas", {
        credentials: "include",
      });
      const data = await response.json();
      setSalas(data);
    } catch (error) {
      console.error(error);
    }
  };

  useEffect(() => {
    obtenerSalas();
  }, []);

  // 🔥 CREAR
  const crearSala = async () => {
    if (!sala.id || !sala.nombre || !sala.ubicacion || !sala.capacidad) {
      alert("Todos los campos son obligatorios");
      return;
    }

    try {
      const response = await fetch("http://localhost:3001/api/salas", {
        method: "POST",
        credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          id: sala.id,
          nombre: sala.nombre,
          ubicacion: sala.ubicacion,
          capacidad: Number(sala.capacidad),
          estado: "disponible"
        }),
      });

      const data = await response.json();

      if (!response.ok) {
        alert(JSON.stringify(data));
        return;
      }

      alert("Sala creada ✅");
      setShowModal(false);
      obtenerSalas();

      setSala({
        id: "",
        nombre: "",
        ubicacion: "",
        capacidad: ""
      });

    } catch (error) {
      console.error(error);
    }
  };

  // 🔥 EDITAR INFO
  const editarInfo = async () => {
    if (!selectedSala) return;

    await fetch(
      `http://localhost:3001/api/salas/${selectedSala.id}/datos`,
      {
        method: "PUT",
        credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          nombre: editForm.nombre,
          ubicacion: editForm.ubicacion,
          capacidad: Number(editForm.capacidad)
        })
      }
    );

    alert("Información actualizada ✅");
    obtenerSalas();
  };

  // 🔥 EDITAR ESTADO
  const editarEstado = async () => {
    if (!selectedSala) return;

    await fetch(
      `http://localhost:3001/api/salas/${selectedSala.id}`,
      {
        method: "PUT",
        credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          estado: editEstado.toLowerCase()
        })
      }
    );

    alert("Estado actualizado ✅");
    obtenerSalas();
  };

  return (
    <div className="container">
      <NavbarGestionSalas userRole={user?.rol || ""} />

      {/* HEADER */}
      <div className="header">
        <h2>Gestión de Salas</h2>
        <button className="btn-crear" onClick={() => setShowModal(true)}>
          + Crear Sala
        </button>
      </div>

      {/* GRID */}
      <div className="grid-salas">
        {salas.map((s) => (
          <div key={s.id} className="card">
            <div className="card-content">
              <h3>{s.nombre}</h3>
              <p>{s.ubicacion}</p>

              <div className="card-info">
                <span>👥 {s.capacidad}</span>
                <span className={`estado ${s.estado}`}>
                  {s.estado}
                </span>
              </div>
            </div>

            <div className="overlay">
              {/* VER INFO */}
              <button
                onClick={() => {
                  setSelectedSala(s);
                  setShowInfoModal(true);
                }}
              >
                Ver Info
              </button>

              <button>Recursos</button>

              {/* EDITAR */}
              <button
                className="editar"
                onClick={() => {
                  setSelectedSala(s);
                  setShowEditModal(true);

                  setEditForm({
                    nombre: s.nombre,
                    ubicacion: s.ubicacion,
                    capacidad: s.capacidad
                  });

                  setEditEstado(s.estado);
                  setEditTab("info");
                }}
              >
                Editar
              </button>
            </div>
          </div>
        ))}
      </div>

      {/* MODAL CREAR */}
      {showModal && (
        <div className="modal-overlay">
          <div className="modal">
            <h3>Crear Sala</h3>

            <input
              placeholder="Código"
              value={sala.id}
              onChange={(e) => setSala({ ...sala, id: e.target.value })}
            />
            <input
              placeholder="Nombre"
              value={sala.nombre}
              onChange={(e) => setSala({ ...sala, nombre: e.target.value })}
            />
            <input
              placeholder="Ubicación"
              value={sala.ubicacion}
              onChange={(e) => setSala({ ...sala, ubicacion: e.target.value })}
            />
            <input
              type="number"
              placeholder="Capacidad"
              value={sala.capacidad}
              onChange={(e) =>
                setSala({ ...sala, capacidad: e.target.value })
              }
            />

            <div className="modal-buttons">
              <button className="cancelar" onClick={() => setShowModal(false)}>
                Cancelar
              </button>
              <button className="crear" onClick={crearSala}>
                Crear
              </button>
            </div>
          </div>
        </div>
      )}

      {/* MODAL INFO */}
      {showInfoModal && selectedSala && (
        <div className="modal-overlay">
          <div className="modal info-modal">
            <h3>Información</h3>

            <p><strong>ID:</strong> {selectedSala.id}</p>
            <p><strong>Nombre:</strong> {selectedSala.nombre}</p>
            <p><strong>Ubicación:</strong> {selectedSala.ubicacion}</p>
            <p><strong>Capacidad:</strong> {selectedSala.capacidad}</p>
            <p>
              <strong>Estado:</strong>
              <span className={`estado ${selectedSala.estado}`}>
                {selectedSala.estado}
              </span>
            </p>

            <div className="modal-buttons">
              <button className="cancelar" onClick={() => setShowInfoModal(false)}>
                Cerrar
              </button>
            </div>
          </div>
        </div>
      )}

      {/* MODAL EDITAR */}
      {showEditModal && selectedSala && (
        <div className="modal-overlay">
          <div className="modal">

            <h3>Editar Sala</h3>

            {/* TABS */}
            <div className="tabs">
              <button
                className={editTab === "info" ? "active" : ""}
                onClick={() => setEditTab("info")}
              >
                Info
              </button>
              <button
                className={editTab === "estado" ? "active" : ""}
                onClick={() => setEditTab("estado")}
              >
                Estado
              </button>
            </div>

            {/* INFO */}
            {editTab === "info" && (
              <>
                <input
                  value={editForm.nombre}
                  onChange={(e) =>
                    setEditForm({ ...editForm, nombre: e.target.value })
                  }
                  placeholder="Nombre"
                />
                <input
                  value={editForm.ubicacion}
                  onChange={(e) =>
                    setEditForm({ ...editForm, ubicacion: e.target.value })
                  }
                  placeholder="Ubicación"
                />
                <input
                  type="number"
                  value={editForm.capacidad}
                  onChange={(e) =>
                    setEditForm({ ...editForm, capacidad: e.target.value })
                  }
                  placeholder="Capacidad"
                />

                <button className="crear" onClick={editarInfo}>
                  Guardar Cambios
                </button>
              </>
            )}

            {/* ESTADO */}
            {editTab === "estado" && (
              <>
                <select
                  value={editEstado}
                  onChange={(e) => setEditEstado(e.target.value)}
                >
                  <option value="">Seleccione</option>
                  <option value="disponible">Disponible</option>
                  <option value="ocupado">Ocupado</option>
                  <option value="mantenimiento">Mantenimiento</option>
                </select>

                <button className="crear" onClick={editarEstado}>
                  Actualizar Estado
                </button>
              </>
            )}

            <div className="modal-buttons">
              <button className="cancelar" onClick={() => setShowEditModal(false)}>
                Cerrar
              </button>
            </div>

          </div>
        </div>
      )}

      <footer className="footer">
        <p>Sistema de Gestión de Salas © 2026</p>
      </footer>
    </div>
  );
}

export default GestionarSalas;
